class Solution:
    def balancedString(self, s: str) -> int:
        from collections import Counter
        n = len(s)
        k = n // 4
        cnt = Counter(s)
        if all(cnt[c] == k for c in 'QWER'):
            return 0
        best = n
        # O(n^2) brute: try every substring
        for i in range(n):
            tmp = Counter(s)
            for j in range(i, n):
                tmp[s[j]] -= 1
                if all(tmp[c] <= k for c in 'QWER'):
                    best = min(best, j - i + 1)
                    break
        return best

