var balancedString = function(s) {
    const n = s.length;
    const k = n >> 2;
    const cnt = {Q:0, W:0, E:0, R:0};
    for (const c of s) cnt[c]++;
    if (Object.values(cnt).every(v => v === k)) return 0;
    const ok = () => Object.values(cnt).every(v => v <= k);
    let res = n, l = 0;
    for (let r = 0; r < n; r++) {
        cnt[s[r]]--;
        while (l <= r && ok()) {
            res = Math.min(res, r - l + 1);
            cnt[s[l]]++;
            l++;
        }
    }
    return res;
};
